import streamlit as stimport plotly.express as pximport plotly.graph_objects as gofrom utils.data_utils import load_dataset, get_kpis, get_risk_colorfrom config import MOIS_L, JOURSdef render():    st.markdown("""    <div class='page-header'>        <h1>🏠 Dashboard Global</h1>        <p>Vue d'ensemble — données batch_1.db</p>    </div>""", unsafe_allow_html=True)    # Curseur dans la sidebar pour choisir la taille de l'échantillon    with st.sidebar:        st.markdown("### ⚙️ Configuration")        sample_size = st.slider(            "Nombre de vols à charger (échantillon)",            min_value=1000, max_value=100000, value=50000, step=1000,            help="Charge un échantillon aléatoire. Réduisez si l'application est lente ou plante."        )    with st.spinner(f"Chargement d'un échantillon de {sample_size:,} vols..."):        df = load_dataset(sample_size=sample_size)    kpis = get_kpis(df)    # --- (le reste du code inchangé) ---    c1,c2,c3,c4,c5 = st.columns(5)    with c1: st.metric("✈️ Vols analysés",    f"{kpis['total_vols']:,}")    with c2: st.metric("⚠️ Taux de retard",   f"{kpis['taux_retard']:.1f}%",                        delta=f"{kpis['taux_retard']-25:.1f}% vs benchmark", delta_color="inverse")    with c3: st.metric("⏱️ Retard moyen",     f"{kpis['retard_moyen']:.0f} min",  help="Vols retardés uniquement")    with c4: st.metric("🚨 Retards sévères",  f"{kpis['pct_severe']:.1f}%",       help=">60 min")    with c5: st.metric("🏢 Compagnies",       f"{kpis['nb_compagnies']}")    st.markdown("<br>", unsafe_allow_html=True)    with st.expander("🔧 Filtres", expanded=False):        cf1,cf2,cf3 = st.columns(3)        with cf1:            annees    = sorted(df["ANNEE"].dropna().unique().astype(int))            sel_annee = st.multiselect("Année", annees, default=annees)        with cf2:            comps    = ["Toutes"] + sorted(df["NOM_COMPAGNIE"].dropna().unique())            sel_comp = st.selectbox("Compagnie", comps)        with cf3:            pays_l   = ["Tous"] + sorted(df["PAYS_DEP"].dropna().unique())            sel_pays = st.selectbox("Pays départ", pays_l)    df_f = df[df["ANNEE"].isin(sel_annee)].copy()    if sel_comp != "Toutes": df_f = df_f[df_f["NOM_COMPAGNIE"] == sel_comp]    if sel_pays != "Tous":   df_f = df_f[df_f["PAYS_DEP"] == sel_pays]    layout_common = dict(plot_bgcolor="rgba(0,0,0,0)", paper_bgcolor="rgba(0,0,0,0)", font_color="#F0F4F8")    # ── Row 1 ──────────────────────────────────────────────────    r1l, r1r = st.columns([3,2])    with r1l:        ts = df_f.groupby(["ANNEE","MOIS"])["RETARD_BIN"].mean().reset_index()        ts["label"] = ts["MOIS"].apply(lambda x: MOIS_L[int(x)-1] if 1<=x<=12 else "?")        fig = px.line(ts, x="label", y="RETARD_BIN", color="ANNEE", markers=True,                      title="📈 Évolution mensuelle du taux de retard",                      labels={"RETARD_BIN":"Taux","label":"Mois","ANNEE":"Année"})        fig.update_layout(**layout_common, yaxis_tickformat=".0%")        fig.add_hline(y=df_f["RETARD_BIN"].mean(), line_dash="dot", line_color="#6B7280",                      annotation_text="Moyenne")        st.plotly_chart(fig, use_container_width=True)    with r1r:        vc  = df_f["RETARD_BIN"].value_counts()        fig2 = go.Figure(go.Pie(            labels=["À l'heure","En retard"], values=vc.values, hole=0.6,            marker_colors=["#2ECC71","#E74C3C"], textfont_size=13,        ))        fig2.update_layout(**layout_common, title="Répartition globale",                           annotations=[dict(text=f"{df_f['RETARD_BIN'].mean()*100:.1f}%",                                             x=0.5, y=0.5, font_size=24, font_color="#E94560", showarrow=False)])        st.plotly_chart(fig2, use_container_width=True)    # ── Row 2 ──────────────────────────────────────────────────    r2l, r2r = st.columns(2)    with r2l:        top_comp = (df_f.groupby("NOM_COMPAGNIE")["RETARD_BIN"]                    .agg(["mean","count"]).reset_index()                    .sort_values("mean", ascending=False).head(10))        top_comp.columns = ["Compagnie","Taux","Volume"]        fig3 = px.bar(top_comp, x="Taux", y="Compagnie", orientation="h",                      color="Taux", color_continuous_scale=["#2ECC71","#F39C12","#E74C3C"],                      title="🏆 Top 10 compagnies — Taux de retard",                      labels={"Taux":"Taux","Compagnie":""}, text_auto=".1%")        fig3.update_layout(**layout_common, xaxis_tickformat=".0%",                           coloraxis_showscale=False, yaxis=dict(autorange="reversed"))        st.plotly_chart(fig3, use_container_width=True)    with r2r:        hm = (df_f.pivot_table(index="NOM_MOIS", columns="NOM_JOUR",                                values="RETARD_BIN", aggfunc="mean") * 100)        try:            hm = hm.reindex(columns=[j for j in JOURS if j in hm.columns])        except Exception:            pass        fig4 = px.imshow(hm, text_auto=".1f", color_continuous_scale="RdYlGn_r",                         title="🗓️ Heatmap Mois × Jour (%)", aspect="auto")        fig4.update_layout(**layout_common)        st.plotly_chart(fig4, use_container_width=True)    # ── Carte ──────────────────────────────────────────────────    st.markdown("### 🗺️ Carte des aéroports de départ")    ap_geo = (df_f.groupby(["AP_DEP","LAT_DEP","LON_DEP"])              .agg(nb=("RETARD_BIN","count"), taux=("RETARD_BIN","mean"))              .reset_index().dropna(subset=["LAT_DEP","LON_DEP"]))    ap_geo["Taux_pct"] = (ap_geo["taux"]*100).round(1)    ap_geo["size"]     = (ap_geo["nb"]/ap_geo["nb"].max()*40).clip(5)    fig5 = px.scatter_geo(ap_geo, lat="LAT_DEP", lon="LON_DEP",                          size="size", color="Taux_pct",                          hover_name="AP_DEP",                          color_continuous_scale="RdYlGn_r",                          projection="natural earth",                          title="Taille = volume | Couleur = taux retard")    fig5.update_layout(**layout_common,                       geo=dict(bgcolor="rgba(0,0,0,0)", landcolor="#1F2937",                                showocean=True, oceancolor="#0A0E1A",                                showcountries=True, countrycolor="#374151"))    st.plotly_chart(fig5, use_container_width=True)